#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 1e4+5;
LL n,a[N],mn,sum;set<int> Ans;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool check(LL L){
    set<int> tmp;tmp.clear();
    for(int i=1;i<=n;i++){
        tmp.insert(a[i]%L);
        if(tmp.size()>3)return 0;
    }return 1;
}
int main(){
    n=read(),mn=5e9;
    for(int i=1;i<=n;i++)
        a[i]=read(),mn=min(mn,a[i]);
    sort(a+1,a+n+1);
    n=unique(a+1,a+n+1)-a-1;
    if(n<=3){
        cout<<(mn/4)*(mn/4+1)/2<<"\n";
        return 0;
    }for(int i=1;i<4;i++)
        for(int j=i+1;j<=4;j++){
            LL k=abs(a[i]-a[j]);
            for(LL x=1;x*x<=k&&x*4<=mn;x++){
                if(k%x)continue;
                if(check(x))Ans.insert(x);
                LL y=k/x;
                if(y*4<=mn&&check(y))Ans.insert(y);
            }
        }
    for(LL x:Ans)sum+=x;cout<<sum<<"\n";
    return 0;
}
